var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"이 녀석들, 평범한 침식체들과 달라!","JPN":"こいつら、普通の侵食体とは違う！","ENG":"These guys aren't your average C.O.!","TWN":"他們不是普通的侵蝕體！"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그래. 리플레이서 융합체들도 이렇게 전술적으로 움직이지는 못했는데…….","JPN":"うん。リプレイサー融合体もここまで戦術的に動けてなかったのに……","ENG":"You're right. Even the Replacer Hybriders couldn't move this tactically…","TWN":"沒錯，克隆集團 融合體也不會像這樣有戰略性地移動……"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"이대로 숫자가 더 늘어나면 위험하겠어.","JPN":"このまま数が増えたら危ない。","ENG":"It could get really dangerous if they grow in number.","TWN":"這樣下去他們的數量只會越來越多，情況會對我們不利。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그러니 우두머리부터 처리하는 게 정답이지!","JPN":"だからボスから処理しなくちゃ！","ENG":"When in doubt, get rid of the boss!","TWN":"先把帶頭的處理掉才是上上策！"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"좋은 판단이에요.","JPN":"良い判断ですね。","ENG":"A keen judgment.","TWN":"你說的沒錯。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"허나 그 하찮은 힘으로 제게 도전하다니, 자신의 역량을 너무 과대평가 하고 있군요.","JPN":"しかし、その程度の実力で私に挑むとは、自分の力量を過大評価していますね。","ENG":"However, you seem to overestimate your own ability, challenging me with such pathetic power.","TWN":"不過就憑你那點微薄之力也想挑戰我，看來你太高估你的能力了。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"성녀라더니 말이 좀 험하시네? 타락 성녀라서 그런가?","JPN":"聖女様と言うわりには口が悪いね。堕落した聖女だからかな？","ENG":"You've got quite the potty mouth for a saintess. Is it because you're a fallen one?","TWN":"你不是聖女嗎？怎麼說話一點也不溫柔？還是因為你是墮落的聖女？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"하지만 걱정하지 마.","JPN":"でも心配しないで。","ENG":"Don't worry though.","TWN":"不過你放心，"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"이걸로 찔러 주면 다들 성격 교정이 잘 되더라고.","JPN":"これを刺してやれば、その悪い性格も治るから。","ENG":"One little stab with this, and everyone seems to behave themselves.","TWN":"只要被這個打過都會變乖喔！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"미스틸테인, 기동!","JPN":"ミスティルテイン、起動！","ENG":"Trigger Misteltein!","TWN":"米斯特丁發動！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"큭?! 먼지가 날려서 잘 안 보여……!","JPN":"くっ！？　ほこりのせいでよく見えない……！","ENG":"Ngh! I can’t see through all the dust!","TWN":"嗯？！都是灰塵看不清楚……！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"어때! 쓰러트렸어?!","JPN":"どう！？　倒した！？","ENG":"Well? Did we get her?!","TWN":"怎麼樣？打敗她的了嗎？！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"서윤?","JPN":"シズカ？","ENG":"Seo Yoon?","TWN":"徐芸？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"아니, 전혀 안 통한 것 같아.","JPN":"いや、まったく効いていない。","ENG":"I don't think it worked at all.","TWN":"怎麼會？對她完全沒用？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"저런 괴물이…… 대체 어디서 나타난 거지?","JPN":"あの化け物……いったいどこから現れたの？","ENG":"Where did such a… monster come from?","TWN":"這是什麼樣的怪物……她到底是從哪裡來的？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그 창은……. 선택 받지 못한 자들이 신성한 존재를 모독하기 위해 만든 무기로군요.","JPN":"その槍は……選ばれなかった者たちが聖なる存在を冒涜するために作った武器ですね。","ENG":"That lance… It's a weapon forged by the unchosen to blaspheme against the divine beings.","TWN":"看來那把槍……是未獲得揀選之人用來侮辱神聖之人的武器。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};